object.Code:
__rtParams = {};

/**
 * Replaces the last '-'-separated segment of context.currentNode.id with the supplied nodeId.
 * Returns the original nodeId untouched when context.currentNode.id is not set.
 *
 * @param {string|number} nodeId - The short id to splice into the current node path.
 * @returns {string} The fully-qualified node id, or the original nodeId if no path is set.
 */
__makeLocalNodeId = function (nodeId) {
    if (nodeId !== null && nodeId !== undefined) nodeId = nodeId.toString();
    if (!context.currentNode.id) return nodeId;
    var __separator = '-';
    var __output = context.currentNode.id.split(__separator);
    __output[__output.length - 1] = nodeId;
    return __output.join(__separator);
};

/**
 * Normalises operation config: JSON string -> parsed; { Params: {...} } -> Params; flat object -> itself; null -> {}.
 *
 * @param {string|object} config - Raw operation config.
 * @returns {object} Flat Params object, never null.
 */
__extractParams = function (config) {
    var __parsed = typeof config === 'string' ? JSON.parse(config) : config;
    if (__parsed && typeof __parsed.Params === 'object' && __parsed.Params !== null) return __parsed.Params;
    return __parsed || {};
};

/**
 * Component-local alias for the global activeFlag() (rtds_3_vocallsEnv.js) —
 * the single Active-coercion contract. See conventions/params.md.
 *
 * @param {*} value
 * @returns {boolean}
 */
__activeFlag = function (value) {
    return activeFlag(value);
};

/**
 * Resolves Params into a flat { Key: value } map. The value's TYPE is whatever
 * the JSON wrote — no Number coercion ('4' stays a string, 4 stays a number).
 * Per key: array-form [value, ...flags] is unwrapped to [0] (matches the runtime
 * twin getParam; isDisplayed/isEditable flags are runtime-irrelevant). Active is
 * then coerced to a real boolean via __activeFlag. Every other STRING value is
 * trimmed and has ${name} placeholders resolved via resolveConfigTokens (varObj
 * first, then global; bare names only; String.replace, never new Function).
 * Non-strings pass through with their type intact. Active absent: not defaulted
 * here — the read site decides (SetVariables true, Send and guard default false).
 *
 * @param {string|object} config - Raw operation config.
 * @returns {object} Map of Key -> resolved value (no __rt prefix; v2 shape).
 */
__setupConfig = function (config) {
    var __params = __extractParams(config);
    var __result = {};
    var __keys = Object.keys(__params);
    for (var __i = 0; __i < __keys.length; __i++) {
        var __key = __keys[__i];
        var __value = __params[__key];
        if (Array.isArray(__value)) __value = __value.length ? __value[0] : '';
        if (__key === 'Active') { __result.Active = __activeFlag(__value); continue; }
        if (typeof __value === 'string') __value = resolveConfigTokens(__value.trim(), __key);
        __result[__key] = __value;
    }
    return __result;
}

